/* ───────── 단어 카드 ───────── */
function CardsScreen({ learned, markLearned }) {
  const [mode, setMode] = useState("lib");
  const [setId, setSetId] = useState(null);
  const [dayIdx, setDayIdx] = useState(null);
  const [idx, setIdx] = useState(0);
  const [flip, setFlip] = useState(false);
  const [justGot, setJustGot] = useState(false);
  const [mnMap, setMnMap] = useState({});
  const [mnLoading, setMnLoading] = useState(false);
  const [mnErr, setMnErr] = useState("");

  useEffect(() => {
    try { const m = localStorage.getItem("tita-mn-v1"); if (m) setMnMap(JSON.parse(m)); } catch (e) {}
  }, []);

  const dayList = mode === "hs" ? DAYS_HS : DAYS;
  const words = mode === "special"
    ? (setId ? SETS.find((s) => s.id === setId).words : null)
    : (dayIdx !== null ? dayList[dayIdx] : null);

  if (!words) {
    return (
      <div className="flex flex-col gap-3">
        <ModeTabs mode={mode} setMode={(m) => { setMode(m); setSetId(null); setDayIdx(null); }} />
        {mode === "special" ? (
          <SetPicker title="연상법이 미리 들어 있는 특제 세트예요." learned={learned}
            onPick={(id) => { setSetId(id); setIdx(0); setFlip(false); }} />
        ) : (
          <LibDayGrid days={dayList} learned={learned} onPick={(i) => { setDayIdx(i); setIdx(0); setFlip(false); }} />
        )}
      </div>
    );
  }

  const w = words[idx];
  const isLearned = !!learned[w.en];
  const mn = w.mn || mnMap[w.en] || null;
  const title = mode === "special" ? SETS.find((s) => s.id === setId).name + " 세트" : (mode === "hs" ? "고등 3000" : "중학 1800") + " · Day " + (dayIdx + 1);
  const tint = mode === "special" ? SETS.find((s) => s.id === setId).tint : mode === "hs" ? C.teal : C.brass;

  const goBack = () => { setSetId(null); setDayIdx(null); setFlip(false); setIdx(0); setMnErr(""); };
  const next = () => { setFlip(false); setJustGot(false); setMnErr(""); setIdx((i) => (i + 1) % words.length); };

  const makeMn = async () => {
    if (mnLoading) return;
    setMnLoading(true); setMnErr("");
    try {
      const res = await fetch("/api/mnemonic", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ word: w.en, meaning: w.ko }),
      });
      const d = await res.json();
      if (d && d.mn) {
        const nm = { ...mnMap, [w.en]: d.mn };
        setMnMap(nm);
        try { localStorage.setItem("tita-mn-v1", JSON.stringify(nm)); } catch (e) {}
      } else {
        setMnErr((d && d.error) || "연상법 생성 실패 — 잠시 후 다시 눌러 주세요");
      }
    } catch (e) { setMnErr("연결 오류 — 다시 시도해 주세요"); }
    setMnLoading(false);
  };

  return (
    <div className="flex flex-col gap-3">
      <div className="flex items-center gap-2">
        <button onClick={goBack} className="p-1 rounded-lg press" style={{ color: C.copper }}><ChevronLeft size={22} /></button>
        <span className="font-bold" style={{ color: C.ink, fontFamily: "'Jua', sans-serif" }}>{title}</span>
        <span className="ml-auto text-xs" style={{ color: C.inkSoft }}>{idx + 1} / {words.length}</span>
      </div>

      <div onClick={() => setFlip(!flip)} role="button" className="text-left w-full press cursor-pointer" aria-label="카드 뒤집기">
        <Panel className="min-h-64 flex flex-col justify-center" style={{ borderColor: tint, borderWidth: 2 }}>
          {!flip ? (
            <div className="text-center py-6 pop">
              <p className="text-xs mb-3 tracking-widest" style={{ color: C.inkSoft }}>NO.{String(idx + 1).padStart(2, "0")} 부품</p>
              <p className="text-4xl font-bold mb-2" style={{ color: C.ink, fontFamily: "'Jua', sans-serif" }}>{w.en}</p>
              {w.pron ? <p className="text-sm mb-4" style={{ color: C.inkSoft }}>[{w.pron}]</p> : <div className="mb-4" />}
              <span className="inline-flex items-center gap-1 text-xs rounded-full px-3 py-1" style={{ background: C.paper, border: "1px solid " + C.copperSoft, color: C.copper }}>
                탭해서 뜻 보기
              </span>
            </div>
          ) : (
            <div className="pop">
              <p className="text-2xl font-bold" style={{ color: C.ink, fontFamily: "'Jua', sans-serif" }}>
                {w.en} <span className="text-base" style={{ color: C.pinkDeep }}>= {w.ko}</span>
              </p>
              {mn ? (
                <div className="mt-3 rounded-xl p-3 text-sm leading-relaxed" style={{ background: C.paper, border: "2px dashed " + C.copper, color: C.ink }}>
                  <span className="font-bold" style={{ color: C.copper }}>💡 연상법</span>
                  {!w.mn ? (
                    <button onClick={(e) => { e.stopPropagation(); makeMn(); }} disabled={mnLoading}
                      className="ml-2 text-xs font-bold press" style={{ color: C.pinkDeep }}>
                      {mnLoading ? "만드는 중…" : "🔄 더 쉽게"}
                    </button>
                  ) : null}
                  <br />{mn}
                </div>
              ) : (
                <div className="mt-3">
                  <button onClick={(e) => { e.stopPropagation(); makeMn(); }} disabled={mnLoading}
                    className="w-full rounded-xl py-2 text-sm font-bold press"
                    style={{ background: C.pinkSoft, border: "2px dashed " + C.pink, color: C.pinkDeep, opacity: mnLoading ? 0.6 : 1 }}>
                    {mnLoading ? "티타가 연상법 만드는 중…" : "✨ AI 연상법 만들기"}
                  </button>
                  {mnErr ? <p className="text-xs mt-1" style={{ color: C.red }}>{mnErr}</p> : null}
                </div>
              )}
              {w.ex ? (
                <div className="mt-3 text-sm leading-relaxed" style={{ color: C.ink }}>
                  <p className="font-medium">“{w.ex}”</p>
                  <p className="text-xs mt-1" style={{ color: C.inkSoft }}>{w.exKo}</p>
                </div>
              ) : null}
            </div>
          )}
        </Panel>
      </div>

      <div className="flex gap-2">
        <button onClick={() => titaSpeak(w.en)} className="rounded-xl px-3 py-3 press" aria-label="발음 듣기"
          style={{ background: C.card, border: "2px solid " + C.copperSoft, color: C.copper }}>
          <Volume2 size={20} />
        </button>
        <button onClick={next} className="flex-1 rounded-xl py-3 font-bold press"
          style={{ background: C.card, border: "2px solid " + C.copperSoft, color: C.inkSoft }}>
          <RotateCcw size={16} className="inline mr-1" /> 다시 볼래요
        </button>
        <button
          onClick={() => { if (!isLearned) { markLearned(w.en); setJustGot(true); } setTimeout(next, isLearned ? 0 : 500); }}
          className="flex-1 rounded-xl py-3 font-bold press"
          style={{ background: isLearned ? C.tealSoft : C.pink, border: "2px solid " + (isLearned ? C.teal : C.pinkDeep), color: isLearned ? C.teal : "#fff" }}>
          {isLearned ? (<><Check size={16} className="inline mr-1" />조립 완료</>) : "외웠어요! +10XP"}
        </button>
      </div>
      {justGot && (
        <p className="text-center text-sm font-bold pop" style={{ color: C.teal }}>
          <Sparkles size={14} className="inline mr-1" />부품 조립 완료! 티타가 기뻐해요!
        </p>
      )}
    </div>
  );
}

/* ───────── 퀴즈 ───────── */
function QuizScreen({ learned, addXp }) {
  const [mode, setMode] = useState("lib");
  const [phase, setPhase] = useState("pick");
  const [qs, setQs] = useState([]);
  const [qi, setQi] = useState(0);
  const [picked, setPicked] = useState(null);
  const [score, setScore] = useState(0);
  const [msg, setMsg] = useState("");
  const [wrongList, setWrongList] = useState([]);
  const [quizStat, setQuizStat] = useState({ count: 0, correct: 0, wrong: {} });
  useEffect(() => {
    try { const q = JSON.parse(localStorage.getItem("tita-quiz-v1") || "{}"); setQuizStat({ count: q.count || 0, correct: q.correct || 0, wrong: q.wrong || {} }); } catch (e) {}
  }, [phase]);
  const saveQuiz = (finalScore, wrongs) => {
    try {
      const q = JSON.parse(localStorage.getItem("tita-quiz-v1") || "{}");
      q.count = (q.count || 0) + 1;
      q.correct = (q.correct || 0) + finalScore;
      q.wrong = q.wrong || {};
      wrongs.forEach((w) => { q.wrong[w.en] = { ko: w.ko, n: ((q.wrong[w.en] && q.wrong[w.en].n) || 0) + 1 }; });
      localStorage.setItem("tita-quiz-v1", JSON.stringify(q));
    } catch (e) {}
  };

  const dayList = mode === "hs" ? DAYS_HS : DAYS;
  const startPool = (pool) => {
    const chosen = shuffle(pool).slice(0, 5);
    const built = chosen.map((w) => {
      const wrong = shuffle(QUIZ_POOL.filter((x) => x.en !== w.en && x.ko !== w.ko)).slice(0, 3).map((x) => x.ko);
      return { w, choices: shuffle([w.ko, ...wrong]) };
    });
    setQs(built); setQi(0); setScore(0); setPicked(null); setMsg(""); setWrongList([]); setPhase("play");
  };

  const topWrong = Object.entries(quizStat.wrong || {}).sort((a, b) => b[1].n - a[1].n).slice(0, 5);
  if (phase === "pick") {
    return (
      <div className="flex flex-col gap-3">
        {quizStat.count > 0 && (
          <Panel className="text-xs" style={{ color: C.ink }}>
            <p className="font-bold" style={{ color: C.copper, fontFamily: "'Jua', sans-serif" }}>
              📊 지금까지 푼 퀴즈 {quizStat.count}회 · 맞힌 부품 {quizStat.correct}개
            </p>
            {topWrong.length > 0 && (
              <div className="mt-2">
                <p className="mb-1" style={{ color: C.inkSoft }}>자주 틀리는 부품 (여기부터 다시 조여요!)</p>
                <div className="flex flex-wrap gap-1">
                  {topWrong.map(([en, info]) => (
                    <span key={en} className="rounded-lg px-2 py-1" style={{ background: C.redSoft, border: "1px solid " + C.red, color: C.red }}>
                      {en} = {info.ko} <b>×{info.n}</b>
                    </span>
                  ))}
                </div>
              </div>
            )}
          </Panel>
        )}
        <ModeTabs mode={mode} setMode={setMode} />
        {mode === "special" ? (
          <SetPicker title="퀴즈는 딱 5문제! 짧고 굵게 가요." learned={learned}
            onPick={(id) => startPool(id === "all" ? ALL_WORDS : SETS.find((s) => s.id === id).words)} allowAll />
        ) : (
          <>
            <LibDayGrid days={dayList} learned={learned} onPick={(i) => startPool(dayList[i])} />
            <button onClick={() => startPool(mode === "hs" ? HS_WORDS : LIB_WORDS)}
              className="rounded-2xl p-4 font-bold press"
              style={{ background: C.pinkSoft, border: "2px solid " + C.pink, color: C.pinkDeep }}>
              🔩 {mode === "hs" ? "3000개" : "1800개"} 전체 랜덤 퀴즈
            </button>
          </>
        )}
      </div>
    );
  }

  if (phase === "done") {
    const great = score >= 4;
    return (
      <div className="flex flex-col gap-4 items-center pt-6">
        <TitaAvatar mood={great ? "happy" : "normal"} size={130} />
        <p className="text-2xl font-bold" style={{ color: C.ink, fontFamily: "'Jua', sans-serif" }}>{score} / 5 정답!</p>
        <Panel className="w-full text-center text-sm" style={{ color: C.ink }}>
          {great ? "굉장해요! 거의 완벽한 정비예요! 에헤헤 ✨" : score >= 2 ? "좋아요! 틀린 부품은 카드에서 다시 조이면 돼요!" : "괜찮아요! 단어 카드에서 한 번 더 보고 오면 금방이에요!"}
          <p className="mt-2 font-bold" style={{ color: C.copper }}>+{score * 10 + 10} XP 획득</p>
        </Panel>
        <p className="text-xs" style={{ color: C.inkSoft }}>📊 지금까지 총 {quizStat.count}회 풀었어요! 틀린 부품은 자동으로 기록돼요.</p>
        <button onClick={() => setPhase("pick")} className="w-full rounded-xl py-3 font-bold press"
          style={{ background: C.pink, border: "2px solid " + C.pinkDeep, color: "#fff" }}>
          한 번 더!
        </button>
      </div>
    );
  }

  const { w, choices } = qs[qi];
  const answered = picked !== null;
  const pick = (c) => {
    if (answered) return;
    setPicked(c);
    const ok = c === w.ko;
    if (ok) { setScore((s) => s + 1); setMsg(CHEER[Math.floor(Math.random() * CHEER.length)]); }
    else { setMsg(OOPS[Math.floor(Math.random() * OOPS.length)]); setWrongList((prev) => [...prev, w]); }
    if (VOICE_CFG.autoPlay !== false) titaSpeak(ok ? PRAISE_VOICE : ENCOURAGE_VOICE);
  };
  const nextQ = () => {
    if (qi + 1 >= qs.length) { addXp(score * 10 + 10); saveQuiz(score, wrongList); setPhase("done"); }
    else { setQi(qi + 1); setPicked(null); setMsg(""); }
  };

  return (
    <div className="flex flex-col gap-3">
      <div className="flex items-center justify-between text-xs" style={{ color: C.inkSoft }}>
        <span>문제 {qi + 1} / 5</span><span>점수 {score}</span>
      </div>
      <Panel className="text-center py-6">
        <p className="text-xs mb-2" style={{ color: C.inkSoft }}>이 부품의 뜻은?</p>
        <p className="text-3xl font-bold" style={{ color: C.ink, fontFamily: "'Jua', sans-serif" }}>{w.en}</p>
        <button onClick={() => titaSpeak(w.en)} className="mt-2 text-xs inline-flex items-center gap-1 press" style={{ color: C.copper }}>
          <Volume2 size={14} /> 발음 듣기
        </button>
      </Panel>
      <div className="grid gap-2">
        {choices.map((c) => {
          let bg = C.card, bd = C.copperSoft, col = C.ink;
          if (answered) {
            if (c === w.ko) { bg = C.tealSoft; bd = C.teal; col = C.teal; }
            else if (c === picked) { bg = C.redSoft; bd = C.red; col = C.red; }
          }
          return (
            <button key={c} onClick={() => pick(c)} disabled={answered}
              className="rounded-xl py-3 px-4 text-left font-medium press"
              style={{ background: bg, border: "2px solid " + bd, color: col }}>
              {c}
            </button>
          );
        })}
      </div>
      {answered && (
        <div className="pop">
          <TitaSays mood={picked === w.ko ? "happy" : "sad"}>
            {msg}
            {picked !== w.ko && w.mn ? (
              <span className="block mt-2 text-xs rounded-lg p-2" style={{ background: "#FFF", border: "1px dashed " + C.copper }}>
                💡 {w.mn}
              </span>
            ) : null}
            {picked !== w.ko && !w.mn ? (
              <span className="block mt-2 text-xs" style={{ color: C.inkSoft }}>
                정답: {w.ko} — 카드에서 ✨AI 연상법을 만들어 보세요!
              </span>
            ) : null}
          </TitaSays>
          <button onClick={nextQ} className="mt-3 w-full rounded-xl py-3 font-bold press"
            style={{ background: C.pink, border: "2px solid " + C.pinkDeep, color: "#fff" }}>
            {qi + 1 >= qs.length ? "결과 보기" : "다음 문제"}
          </button>
        </div>
      )}
    </div>
  );
}

/* ───────── 필기 연습 패드 (펜·필압 지원, 5줄) ───────── */
function PracticePad({ word }) {
  const canvasRef = useRef(null);
  const wrapRef = useRef(null);
  const strokesRef = useRef([]); // [{pts:[{x,y,lw}]}] 좌표는 0~1 비율로 저장
  const curRef = useRef(null);
  const [penOnly, setPenOnly] = useState(false);
  const ROWS = 5;
  const WRITE_KEY = "tita-write-v1";
  const loadStrokes = () => {
    try {
      const all = JSON.parse(localStorage.getItem(WRITE_KEY) || "{}");
      const raw = all[word];
      if (!raw || !raw.length) return [];
      return raw.map((st) => ({ pts: st.map((p) => ({ x: p[0], y: p[1], lw: p[2] })) }));
    } catch (e) { return []; }
  };
  const saveStrokes = () => {
    try {
      const all = JSON.parse(localStorage.getItem(WRITE_KEY) || "{}");
      if (!strokesRef.current.length) delete all[word];
      else all[word] = strokesRef.current.map((st) =>
        st.pts.map((p) => [Math.round(p.x * 1000) / 1000, Math.round(p.y * 1000) / 1000, Math.round(p.lw * 10) / 10]));
      localStorage.setItem(WRITE_KEY, JSON.stringify(all));
    } catch (e) {}
  };

  useEffect(() => {
    try { if (localStorage.getItem("tita-pen-v1") === "1") setPenOnly(true); } catch (e) {}
  }, []);

  const drawGuides = (ctx, w, h) => {
    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = "#FFFDF8";
    ctx.fillRect(0, 0, w, h);
    const rowH = h / ROWS;
    for (let i = 0; i < ROWS; i++) {
      const y = rowH * (i + 1) - rowH * 0.2;
      ctx.strokeStyle = "#E8C9A8";
      ctx.lineWidth = 1.5;
      ctx.setLineDash([6, 6]);
      ctx.beginPath(); ctx.moveTo(14, y); ctx.lineTo(w - 14, y); ctx.stroke();
      ctx.setLineDash([]);
      ctx.fillStyle = "#C8B49A";
      ctx.font = "12px sans-serif";
      ctx.fillText(String(i + 1), 5, y - 4);
    }
    // 1행: 따라쓰기 본보기 (연한 글씨)
    ctx.fillStyle = "rgba(70,49,37,0.16)";
    ctx.font = '600 ' + Math.min(42, rowH * 0.6) + 'px "Jua", sans-serif';
    ctx.fillText(word, 28, rowH * 0.7);
  };

  const redraw = () => {
    const cv = canvasRef.current; if (!cv) return;
    const ctx = cv.getContext("2d");
    const dpr = window.devicePixelRatio || 1;
    const w = cv.width / dpr, h = cv.height / dpr;
    drawGuides(ctx, w, h);
    ctx.lineCap = "round"; ctx.lineJoin = "round"; ctx.strokeStyle = "#463125";
    for (const s of strokesRef.current) {
      for (let i = 1; i < s.pts.length; i++) {
        const a = s.pts[i - 1], b = s.pts[i];
        ctx.lineWidth = b.lw;
        ctx.beginPath(); ctx.moveTo(a.x * w, a.y * h); ctx.lineTo(b.x * w, b.y * h); ctx.stroke();
      }
    }
  };

  const setup = () => {
    const cv = canvasRef.current, wrap = wrapRef.current;
    if (!cv || !wrap) return;
    const dpr = window.devicePixelRatio || 1;
    const w = wrap.clientWidth;
    const h = ROWS * 72;
    cv.width = w * dpr; cv.height = h * dpr;
    cv.style.width = w + "px"; cv.style.height = h + "px";
    cv.getContext("2d").setTransform(dpr, 0, 0, dpr, 0, 0);
    redraw();
  };

  useEffect(() => {
    strokesRef.current = loadStrokes(); curRef.current = null;
    setup();
    const onR = () => setup();
    window.addEventListener("resize", onR);
    return () => window.removeEventListener("resize", onR);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [word]);

  const pos = (e) => {
    const r = canvasRef.current.getBoundingClientRect();
    return { x: (e.clientX - r.left) / r.width, y: (e.clientY - r.top) / r.height };
  };
  const widthOf = (e) => (e.pointerType === "pen" ? Math.max(1.5, 4.5 * (e.pressure || 0.5)) : 3);

  const down = (e) => {
    if (penOnly && e.pointerType !== "pen") return;
    e.preventDefault();
    try { canvasRef.current.setPointerCapture(e.pointerId); } catch (e2) {}
    const p = pos(e);
    curRef.current = { pts: [{ x: p.x, y: p.y, lw: widthOf(e) }] };
  };
  const move = (e) => {
    if (!curRef.current) return;
    if (penOnly && e.pointerType !== "pen") return;
    e.preventDefault();
    const p = pos(e);
    curRef.current.pts.push({ x: p.x, y: p.y, lw: widthOf(e) });
    const cv = canvasRef.current; const ctx = cv.getContext("2d");
    const dpr = window.devicePixelRatio || 1;
    const w = cv.width / dpr, h = cv.height / dpr;
    const n = curRef.current.pts.length;
    if (n >= 2) {
      const a = curRef.current.pts[n - 2], b = curRef.current.pts[n - 1];
      ctx.lineCap = "round"; ctx.lineJoin = "round"; ctx.strokeStyle = "#463125"; ctx.lineWidth = b.lw;
      ctx.beginPath(); ctx.moveTo(a.x * w, a.y * h); ctx.lineTo(b.x * w, b.y * h); ctx.stroke();
    }
  };
  const up = () => {
    if (!curRef.current) return;
    if (curRef.current.pts.length > 1) strokesRef.current.push(curRef.current);
    curRef.current = null;
    saveStrokes();
  };

  const undo = () => { strokesRef.current.pop(); redraw(); saveStrokes(); };
  const clearAll = () => { strokesRef.current = []; redraw(); saveStrokes(); };
  const togglePen = (v) => { setPenOnly(v); try { localStorage.setItem("tita-pen-v1", v ? "1" : "0"); } catch (e) {} };

  return (
    <div ref={wrapRef} className="w-full">
      <canvas
        ref={canvasRef}
        onPointerDown={down}
        onPointerMove={move}
        onPointerUp={up}
        onPointerCancel={up}
        onContextMenu={(e) => e.preventDefault()}
        className="rounded-2xl w-full"
        style={{ touchAction: "none", border: "2px solid " + C.copperSoft, background: C.card, display: "block", boxShadow: "0 2px 0 rgba(70,49,37,0.08)" }}
      />
      <div className="flex items-center gap-2 mt-2">
        <button onClick={undo} className="rounded-xl px-3 py-2 text-xs font-bold press inline-flex items-center gap-1"
          style={{ background: C.card, border: "2px solid " + C.copperSoft, color: C.inkSoft }}>
          <Undo2 size={14} /> 한 획 취소
        </button>
        <button onClick={clearAll} className="rounded-xl px-3 py-2 text-xs font-bold press inline-flex items-center gap-1"
          style={{ background: C.card, border: "2px solid " + C.copperSoft, color: C.inkSoft }}>
          <Trash2 size={14} /> 지우기
        </button>
        <label className="ml-auto flex items-center gap-1 text-xs font-bold" style={{ color: C.ink }}>
          <input type="checkbox" checked={penOnly} onChange={(e) => togglePen(e.target.checked)} />
          ✍️ 펜만 (손바닥 무시)
        </label>
      </div>
    </div>
  );
}

/* ───────── 필기 노트 (단어 5번 쓰기) ───────── */
function WritingScreen({ learned, markLearned }) {
  const [mode, setMode] = useState("lib");
  const [setId, setSetId] = useState(null);
  const [dayIdx, setDayIdx] = useState(null);
  const [idx, setIdx] = useState(0);
  const [justGot, setJustGot] = useState(false);

  const dayList = mode === "hs" ? DAYS_HS : DAYS;
  const words = mode === "special"
    ? (setId ? SETS.find((s) => s.id === setId).words : null)
    : (dayIdx !== null ? dayList[dayIdx] : null);

  if (!words) {
    return (
      <div className="flex flex-col gap-3">
        <p className="text-xs rounded-lg py-2 px-3" style={{ background: C.paper, border: "1px dashed " + C.copperSoft, color: C.inkSoft }}>
          ✍️ 태블릿 + 펜으로 단어를 5번씩 따라 쓰는 연습장이에요. 1행의 연한 글씨를 따라 쓰고, 나머지 줄은 혼자 써 보세요. 손이 기억해 줘요!
        </p>
        <ModeTabs mode={mode} setMode={(m) => { setMode(m); setSetId(null); setDayIdx(null); }} />
        {mode === "special" ? (
          <SetPicker title="필기로 외울 특제 세트를 골라 주세요." learned={learned}
            onPick={(id) => { setSetId(id); setIdx(0); setJustGot(false); }} />
        ) : (
          <LibDayGrid days={dayList} learned={learned} onPick={(i) => { setDayIdx(i); setIdx(0); setJustGot(false); }} />
        )}
      </div>
    );
  }

  const w = words[idx];
  const isLearned = !!learned[w.en];
  const title = mode === "special" ? SETS.find((s) => s.id === setId).name + " 세트" : (mode === "hs" ? "고등 3000" : "중학 1800") + " · Day " + (dayIdx + 1);
  const goBack = () => { setSetId(null); setDayIdx(null); setIdx(0); setJustGot(false); };
  const go = (d) => { setJustGot(false); setIdx((i) => (i + d + words.length) % words.length); };

  return (
    <div className="flex flex-col gap-3">
      <div className="flex items-center gap-2">
        <button onClick={goBack} className="p-1 rounded-lg press" style={{ color: C.copper }}><ChevronLeft size={22} /></button>
        <span className="font-bold" style={{ color: C.ink, fontFamily: "'Jua', sans-serif" }}>{title}</span>
        <span className="ml-auto text-xs" style={{ color: C.inkSoft }}>{idx + 1} / {words.length}</span>
      </div>

      <Panel className="text-center py-3">
        <p className="text-3xl font-bold" style={{ color: C.ink, fontFamily: "'Jua', sans-serif" }}>
          {w.en} <span className="text-base" style={{ color: C.pinkDeep }}>= {w.ko}</span>
        </p>
        <button onClick={() => titaSpeak(w.en)} className="mt-1 text-xs inline-flex items-center gap-1 press" style={{ color: C.copper }}>
          <Volume2 size={14} /> 발음 듣기
        </button>
      </Panel>

      <PracticePad key={w.en + "-" + idx} word={w.en} />

      <div className="flex gap-2">
        <button onClick={() => go(-1)} className="rounded-xl px-3 py-3 press" aria-label="이전 단어"
          style={{ background: C.card, border: "2px solid " + C.copperSoft, color: C.inkSoft }}>
          <ChevronLeft size={20} />
        </button>
        <button
          onClick={() => { if (!isLearned) { markLearned(w.en); setJustGot(true); setTimeout(() => go(1), 600); } else go(1); }}
          className="flex-1 rounded-xl py-3 font-bold press"
          style={{ background: isLearned ? C.tealSoft : C.pink, border: "2px solid " + (isLearned ? C.teal : C.pinkDeep), color: isLearned ? C.teal : "#fff" }}>
          {isLearned ? (<><Check size={16} className="inline mr-1" />조립 완료</>) : "5번 다 썼어요! +10XP"}
        </button>
        <button onClick={() => go(1)} className="rounded-xl px-3 py-3 press" aria-label="다음 단어"
          style={{ background: C.card, border: "2px solid " + C.copperSoft, color: C.inkSoft }}>
          <ChevronRight size={20} />
        </button>
      </div>
      {justGot && (
        <p className="text-center text-sm font-bold pop" style={{ color: C.teal }}>
          <Sparkles size={14} className="inline mr-1" />손글씨 조립 완료! 티타가 기뻐해요!
        </p>
      )}
    </div>
  );
}

/* ───────── 티타와 회화 (AI — /api/chat 중계) ───────── */
function ChatScreen() {
  const [messages, setMessages] = useState([
    { role: "assistant", data: { english: "Hello, Minwoo oppa! I'm Tita! Let's practice English together. How are you today?", korean: "안녕하세요, 민우 오빠! 저 티타예요! 같이 영어 연습해요. 오늘 기분 어때요?", tip: null } },
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [cfgOpen, setCfgOpen] = useState(false);
  const [autoPlay, setAutoPlay] = useState(true);
  const [voiceMsg, setVoiceMsg] = useState("");
  const endRef = useRef(null);

  useEffect(() => { setAutoPlay(VOICE_CFG.autoPlay !== false); }, []);
  useEffect(() => { endRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, loading]);

  const toggleAuto = (v) => {
    setAutoPlay(v);
    VOICE_CFG.autoPlay = v;
    try { localStorage.setItem("tita-voice-v1", JSON.stringify({ autoPlay: v })); } catch (e) {}
  };

  const testVoice = async () => {
    setVoiceMsg("티타 보이스 테스트 중…");
    const ok = await titaSpeak("Hello! I'm Tita! Nice to meet you!");
    if (ok) { setVoiceMsg("ElevenLabs 티타 보이스 작동 중! 🎉"); return; }
    const err = (typeof window !== "undefined" && window.__titaErr) || { status: 0, detail: "" };
    const s = err.status;
    const d = (err.detail || "").toLowerCase();
    let why;
    if (s === 500 && err.detail && err.detail.includes("환경변수")) why = "❌ Vercel에 환경변수(ELEVENLABS_API_KEY / ELEVENLABS_VOICE_ID)가 없어요 → 넣고 Redeploy 해주세요";
    else if (s === 401 && /permission|subscription|plan|tier/.test(d)) why = "❌ ElevenLabs 무료 플랜이라 API가 막혔어요 → Starter(월 $5) 필요";
    else if (s === 401) why = "❌ [401] ElevenLabs API 키가 틀렸어요 → Vercel 환경변수 값 확인";
    else if (s === 404) why = "❌ [404] Voice ID가 틀렸어요 → 이름 말고 영문+숫자 ID를 넣어야 해요";
    else if (s === 429) why = "❌ [429] 이번 달 글자 잔량 초과";
    else why = "❌ 연결 실패 (" + (err.detail || s) + ") — 지금은 기본 목소리로 재생됐어요";
    setVoiceMsg(why);
  };

  const send = async () => {
    const text = input.trim();
    if (!text || loading) return;
    const newMsgs = [...messages, { role: "user", content: text }];
    setMessages(newMsgs); setInput(""); setLoading(true);
    try {
      const apiMessages = newMsgs.map((m) =>
        m.role === "user" ? { role: "user", content: m.content } : { role: "assistant", content: JSON.stringify(m.data) }
      );
      const res = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ messages: apiMessages }),
      });
      let parsed;
      try { parsed = await res.json(); }
      catch (e2) {
        parsed = { english: "Hmm, my relay desk is missing!", korean: "서버에서 /api/chat 창구를 못 찾았어요 — GitHub의 app/api 폴더가 올라가 있는지 확인해 주세요!", tip: null };
      }
      setMessages([...newMsgs, { role: "assistant", data: parsed }]);
      if (VOICE_CFG.autoPlay && parsed.english) titaSpeak(parsed.english);
    } catch (e) {
      setMessages([...newMsgs, { role: "assistant", data: { english: "Oops! The orbment lost connection...", korean: "앗, 통신이 잠깐 끊겼어요. 다시 한 번 보내 주세요!", tip: null } }]);
    }
    setLoading(false);
  };

  const inputStyle = { background: C.card, border: "2px solid " + C.copperSoft, color: C.ink };

  return (
    <div className="flex flex-col h-full">
      <div className="flex items-stretch gap-2 mb-3">
        <p className="flex-1 text-xs rounded-lg py-2 px-3" style={{ background: C.paper, border: "1px dashed " + C.copperSoft, color: C.inkSoft }}>
          영어로 써도, 한국어로 써도 OK! 티타가 쉬운 영어로 답해 줘요.
        </p>
        <button onClick={() => setCfgOpen(!cfgOpen)} className="text-xs rounded-lg px-3 press shrink-0 font-bold"
          style={{ background: cfgOpen ? C.pinkSoft : C.card, border: "2px solid " + C.pink, color: C.pinkDeep }}>
          🎙️ 목소리
        </button>
      </div>

      {cfgOpen && (
        <div className="rounded-2xl p-4 mb-3 text-sm pop" style={{ background: C.card, border: "2px solid " + C.pink }}>
          <p className="font-bold mb-1" style={{ color: C.ink }}>티타 목소리 설정</p>
          <p className="text-xs mb-3" style={{ color: C.inkSoft }}>
            API 키는 Vercel 서버(환경변수)에 안전하게 보관돼요. 앱에는 입력할 게 없어요!
          </p>
          <label className="flex items-center gap-2 text-xs mb-3" style={{ color: C.ink }}>
            <input type="checkbox" checked={autoPlay} onChange={(e) => toggleAuto(e.target.checked)} />
            티타가 답장하면 자동으로 음성 재생
          </label>
          <div className="flex gap-2">
            <button onClick={playSample} className="flex-1 rounded-lg py-2 text-xs font-bold press"
              style={{ background: C.paper, border: "2px solid " + C.copperSoft, color: C.copper }}>
              🔊 샘플 듣기
            </button>
            <button onClick={testVoice} className="flex-1 rounded-lg py-2 text-xs font-bold press"
              style={{ background: C.tealSoft, border: "2px solid " + C.teal, color: C.teal }}>
              보이스 테스트
            </button>
          </div>
          {voiceMsg && <p className="text-xs mt-2 font-bold" style={{ color: C.copper }}>{voiceMsg}</p>}
        </div>
      )}

      <div className="flex-1 overflow-y-auto flex flex-col gap-3 pb-3">
        {messages.map((m, i) =>
          m.role === "user" ? (
            <div key={i} className="self-end max-w-xs rounded-2xl rounded-br-sm px-4 py-2 text-sm"
              style={{ background: C.copper, color: "#fff" }}>
              {m.content}
            </div>
          ) : (
            <div key={i} className="flex items-end gap-2 max-w-full">
              <div className="shrink-0"><TitaAvatar mood="happy" size={48} /></div>
              <div className="rounded-2xl rounded-bl-sm px-4 py-3 text-sm"
                style={{ background: C.pinkSoft, border: "2px solid " + C.pink, color: C.ink }}>
                <p className="font-medium leading-relaxed">{m.data.english}</p>
                {m.data.korean ? <p className="text-xs mt-1" style={{ color: C.inkSoft }}>{m.data.korean}</p> : null}
                {m.data.tip ? (
                  <p className="text-xs mt-2 rounded-lg p-2" style={{ background: "#FFF", border: "1px dashed " + C.copper, color: C.copper }}>
                    🔧 교정 팁: {m.data.tip}
                  </p>
                ) : null}
                {m.data.english ? (
                  <button onClick={() => titaSpeak(m.data.english)} className="mt-2 text-xs inline-flex items-center gap-1 press" style={{ color: C.pinkDeep }}>
                    <Volume2 size={12} /> 듣기
                  </button>
                ) : null}
              </div>
            </div>
          )
        )}
        {loading && (
          <div className="flex items-end gap-2">
            <div className="shrink-0"><TitaAvatar mood="think" size={48} /></div>
            <div className="rounded-2xl rounded-bl-sm px-4 py-3 text-sm" style={{ background: C.pinkSoft, border: "2px solid " + C.pink, color: C.inkSoft }}>
              티타가 생각 중<span className="dots">...</span>
            </div>
          </div>
        )}
        <div ref={endRef} />
      </div>

      <div className="flex gap-2 pt-2" style={{ borderTop: "2px dashed " + C.copperSoft }}>
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => { if (e.key === "Enter") send(); }}
          placeholder="예) Hello! / 오늘 뭐 했어?"
          className="flex-1 rounded-xl px-4 py-3 text-sm outline-none"
          style={inputStyle}
        />
        <button onClick={send} disabled={loading} className="rounded-xl px-4 press"
          style={{ background: C.pink, border: "2px solid " + C.pinkDeep, color: "#fff", opacity: loading ? 0.6 : 1 }}>
          <Send size={18} />
        </button>
      </div>
    </div>
  );
}

/* ───────── 메인 앱 ───────── */
export default function TitaEnglishWorkshop() {
  const [screen, setScreen] = useState("home");
  const [xp, setXp] = useState(0);
  const [learned, setLearned] = useState({});
  const [greeting, setGreeting] = useState(GREETINGS[0]);

  // 진행도 + 설정 불러오기 (이 브라우저에 저장됨)
  useEffect(() => {
    try {
      const r = localStorage.getItem("tita-english-v1");
      if (r) { const d = JSON.parse(r); setXp(d.xp || 0); setLearned(d.learned || {}); }
    } catch (e) {}
    try {
      const v = localStorage.getItem("tita-voice-v1");
      if (v) Object.assign(VOICE_CFG, JSON.parse(v));
    } catch (e) {}
    setGreeting(GREETINGS[Math.floor(Math.random() * GREETINGS.length)]);
  }, []);

  const persist = (nxp, nlearned) => {
    try { localStorage.setItem("tita-english-v1", JSON.stringify({ xp: nxp, learned: nlearned })); } catch (e) {}
  };
  const addXp = (n) => setXp((x) => { const nx = x + n; persist(nx, learned); return nx; });
  const markLearned = (en) => {
    setLearned((l) => {
      const nl = { ...l, [en]: true };
      setXp((x) => { const nx = x + 10; persist(nx, nl); return nx; });
      return nl;
    });
  };

  const learnedCount = Object.keys(learned).length;
  const { cur } = levelInfo(xp);
  const TITLES = { home: "티타의 영어 정비공방", cards: "단어 카드", write: "필기 노트", quiz: "조립 퀴즈", chat: "티타와 회화" };

  return (
    <div className="min-h-screen flex flex-col" style={{ background: C.paper, fontFamily: "'Gowun Dodum', sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Jua&family=Gowun+Dodum&display=swap');
        .press { transition: transform .08s ease; }
        .press:active { transform: scale(.97); }
        @keyframes bob { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-4px); } }
        .tita-bob { animation: bob 2.4s ease-in-out infinite; }
        @keyframes popin { from { opacity: 0; transform: translateY(6px) scale(.98); } to { opacity: 1; transform: none; } }
        .pop { animation: popin .25s ease; }
        @keyframes spin { to { transform: rotate(360deg); } }
        .gear-spin { animation: spin 8s linear infinite; }
        @keyframes blink { 0%,100% { opacity: .2 } 50% { opacity: 1 } }
        .dots { animation: blink 1s infinite; }
        @media (prefers-reduced-motion: reduce) { * { animation: none !important; transition: none !important; } }
      `}</style>

      {/* 헤더 */}
      <header className="sticky top-0 z-10 px-4 py-3"
        style={{ background: C.paper, borderBottom: `2px solid ${C.copperSoft}` }}>
        <div className="max-w-md mx-auto flex items-center gap-2">
          <Wrench size={20} style={{ color: C.copper }} />
          <h1 className="text-lg" style={{ color: C.ink, fontFamily: "'Jua', sans-serif" }}>{TITLES[screen]}</h1>
          <span className="ml-auto text-xs rounded-full px-3 py-1 font-bold"
            style={{ background: C.pinkSoft, border: `1px solid ${C.pink}`, color: C.pinkDeep }}>
            Lv. {cur.title}
          </span>
        </div>
      </header>

      {/* 본문 */}
      <main className="flex-1 px-4 py-4 pb-24 w-full max-w-md mx-auto" style={{ minHeight: 0 }}>
        {screen === "home" && <HomeScreen xp={xp} learnedCount={learnedCount} go={setScreen} greeting={greeting} />}
        {screen === "cards" && <CardsScreen learned={learned} markLearned={markLearned} />}
        {screen === "write" && <WritingScreen learned={learned} markLearned={markLearned} />}
        {screen === "quiz" && <QuizScreen learned={learned} addXp={addXp} />}
        {screen === "chat" && <div style={{ height: "70vh" }}><ChatScreen /></div>}
      </main>

      {/* 하단 탭 */}
      <nav className="fixed bottom-0 left-0 right-0 z-10" style={{ background: C.card, borderTop: `2px solid ${C.copperSoft}` }}>
        <div className="max-w-md mx-auto grid grid-cols-5">
          {[
            { key: "home", Icon: Home, label: "홈" },
            { key: "cards", Icon: BookOpen, label: "단어" },
            { key: "write", Icon: Pencil, label: "필기" },
            { key: "quiz", Icon: Brain, label: "퀴즈" },
            { key: "chat", Icon: MessageCircle, label: "회화" },
          ].map(({ key, Icon, label }) => {
            const active = screen === key;
            return (
              <button key={key} onClick={() => setScreen(key)} className="flex flex-col items-center gap-1 py-2 press">
                <Icon size={22} style={{ color: active ? C.pinkDeep : C.inkSoft }} />
                <span className="text-xs font-bold" style={{ color: active ? C.pinkDeep : C.inkSoft }}>{label}</span>
              </button>
            );
          })}
        </div>
      </nav>
    </div>
  );
}
